11	import type { AgentEvent } from "./agent/events.ts";
12	import type { ErrorEvent, TextDeltaEvent } from "./ai/events.ts";
13	import type { MinimaAgent } from "./minima/runtime.ts";
14	
15	/** Serialize an AgentEvent into a JSON-friendly dict (PI-style JSON mode). */
16	export function eventToDict(event: AgentEvent): Record<string, unknown> {
17	  if (event.type === "message_update") {
18	    const stream = event.assistantMessageEvent as TextDeltaEvent | ErrorEvent | null;
19	    if (stream?.type === "text_delta") return { type: "text_delta", delta: stream.delta };
20	    if (stream?.type === "error") {
21	      return {
22	        type: "error",
23	        message: stream.error.error_message || "provider error",
24	        model: stream.error.model,
25	      };
26	    }
27	    return { type: "message_update" };
28	  }
29	  if (event.type === "tool_execution_start") return { type: "tool_start", name: event.toolName };
30	  if (event.type === "tool_execution_end") return { type: "tool_end", is_error: event.isError };
31	  if (event.type === "turn_end") return { type: "turn_end" };
32	  if (event.type === "agent_end") return { type: "done" };
33	  if (event.type === "agent_start") return { type: "start" };
34	  return { type: event.type };
35	}
