37	/** One-shot: run the prompt, print the final assistant text, exit. */
38	export async function runPrint(agent: MinimaAgent, prompt: string): Promise<number> {
39	  await agent.promptRouted(prompt);
40	  const messages = agent.agentState.messages;
41	  let text = "";
42	  for (let i = messages.length - 1; i >= 0; i--) {
43	    const m = messages[i]!;
44	    if (m.role === "assistant") {
45	      text = m.textContent;
46	      break;
47	    }
48	  }
49	  const err = agent.offlineReason && !text.trim() ? agent.offlineReason : null;
50	  if (err) {
51	    process.stderr.write(`${err}\n`);
52	    return 1;
53	  }
54	  process.stdout.write(`${text}\n`);
55	  return 0;
56	}
