24	async function readStream(stream: ReadableStream<Uint8Array> | null): Promise<string> {
25	  if (!stream) return "";
26	  const reader = stream.getReader();
27	  const decoder = new TextDecoder();
28	  let out = "";
29	  for (;;) {
30	    const { done, value } = await reader.read();
31	    if (done) break;
32	    out += decoder.decode(value, { stream: true });
33	  }
34	  out += decoder.decode();
35	  return out;
36	}
