38	async function execute(
39	  _id: string,
40	  params: Record<string, unknown>,
41	  signal: AbortSignal | null,
42	  onUpdate: ToolUpdate | null,
43	): Promise<ToolResult> {
44	  const command = String(params.command);
45	  const timeoutMs = (params.timeout as number) ?? 120_000;
46	  const wd = params.workdir ? expand(String(params.workdir)) : undefined;
47	  if (wd && !existsSync(wd)) return errorResult(`bash: workdir does not exist: ${wd}`);
48	  if (wd && !statSync(wd).isDirectory())
49	    return errorResult(`bash: workdir is not a directory: ${wd}`);
50	
51	  let proc: import("bun").Subprocess<"ignore", "pipe", "pipe">;
52	  try {
53	    proc = Bun.spawn(["bash", "-c", command], {
54	      cwd: wd,
55	      stdout: "pipe",
56	      stderr: "pipe",
57	      stdin: "ignore",
58	    });
59	  } catch (exc) {
60	    return errorResult(`bash: failed to start: ${exc}`);
61	  }
62	
63	  const timer = new Promise<"timeout">((resolve) => {
64	    const t = setTimeout(() => resolve("timeout"), timeoutMs);
65	    if (signal) {
66	      signal.addEventListener("abort", () => {
67	        clearTimeout(t);
68	      });
69	    }
70	  });
71	
72	  const aborted = signal
73	    ? new Promise<"aborted">((resolve) =>
74	        signal.addEventListener("abort", () => resolve("aborted")),
75	      )
76	    : new Promise<"aborted">(() => {});
77	
78	  const winner = await Promise.race([
79	    Promise.all([
80	      readStream(proc.stdout ?? null),
81	      readStream(proc.stderr ?? null),
82	      proc.exited,
83	    ]).then(([out, err]) => ({ kind: "done" as const, out, err })),
84	    timer.then((kind) => ({ kind })),
85	    aborted.then((kind) => ({ kind })),
86	  ]);
87	
88	  if (winner.kind === "timeout" || winner.kind === "aborted") {
89	    try {
90	      proc.kill();
91	    } catch {
92	      // already dead
93	    }
94	    return errorResult(
95	      winner.kind === "timeout" ? `bash: timed out after ${timeoutMs} ms` : "bash: aborted",
96	    );
97	  }
98	
99	  const output = `${winner.out}${winner.err}`;
100	  const code = await proc.exited;
101	  const body = output ? `${output}\n[exit ${code}]` : `[exit ${code}]`;
102	  if (onUpdate) {
103	    try {
104	      onUpdate(output);
105	    } catch {
106	      // progress must never break the run
107	    }
108	  }
109	  return { content: [text(body)], details: { exit_code: code } };
