34	/** Compact relative age: just now / 5m ago / 2h ago / 3d ago / 5w ago. */
35	export function formatAge(ts: number, now: number = nowTs()): string {
36	  if (!ts || ts <= 0) return "?";
37	  const delta = Math.max(0, now - ts);
38	  if (delta < 60) return "just now";
