37	async function loadEnvFiles(): Promise<void> {
38	  for (const name of ENV_FILES) {
39	    const path = resolve(name);
40	    if (!existsSync(path)) continue;
41	    const text = readFileSync(path, "utf8");
42	    for (const raw of text.split(/\r?\n/)) {
43	      const line = raw.trim();
44	      if (!line || line.startsWith("#") || !line.includes("=")) continue;
45	      const eq = line.indexOf("=");
46	      const key = line.slice(0, eq).trim();
47	      const val = line
48	        .slice(eq + 1)
49	        .trim()
50	        .replace(/^["']|["']$/g, "");
51	      if (process.env[key] === undefined) process.env[key] = val;
52	    }
53	  }
54	  // Per-user store (OS keychain + ~/.minima-harness/config.env) — lowest precedence, so
55	  // shell env and project .env files still win. Failures never block startup.
56	  try {
57	    await hydrateEnv();
58	  } catch {
59	    // config must never block startup
