164	function parseArgs(argv: string[]): CliArgs {
165	  const opts: CliArgs = {
166	    prompt: [],
167	    thinking: "off",
168	    offline: false,
169	    print: false,
170	    mode: "interactive",
171	    noTools: false,
172	  };
173	  const take = (i: number): string => {
174	    const v = argv[i + 1];
175	    if (v === undefined) throw new Error(`flag ${argv[i]} requires a value`);
176	    return v;
177	  };
178	  for (let i = 0; i < argv.length; i++) {
179	    const a = argv[i]!;
180	    switch (a) {
181	      case "-p":
182	      case "--print":
183	        opts.print = true;
184	        break;
185	      case "--mode":
186	        opts.mode = take(i++) as CliArgs["mode"];
187	        break;
188	      case "--model":
189	        opts.model = take(i++);
190	        break;
191	      case "--provider":
192	        opts.provider = take(i++);
193	        break;
194	      case "--thinking":
195	        opts.thinking = take(i++);
196	        break;
197	      case "--offline":
198	        opts.offline = true;
199	        break;
200	      case "-t":
201	      case "--tools":
202	        opts.tools = take(i++);
203	        break;
204	      case "-xt":
205	      case "--exclude-tools":
206	        opts.excludeTools = take(i++);
207	        break;
208	      case "-nt":
209	      case "--no-tools":
210	        opts.noTools = true;
211	        break;
212	      case "-h":
213	      case "--help":
214	        process.stdout.write(HELP);
215	        process.exit(0);
216	        break;
217	      default:
218	        if (a.startsWith("-")) throw new Error(`unknown flag: ${a}`);
219	        opts.prompt.push(a);
220	    }
221	  }
222	  return opts;
223	}
