243	function toolsFor(args: CliArgs) {
244	  let tools = args.noTools ? [] : builtinTools();
245	  if (args.tools) {
246	    const allow = new Set(args.tools.split(",").map((s) => s.trim()));
247	    tools = tools.filter((t) => allow.has(t.name));
248	  }
249	  if (args.excludeTools) {
250	    const deny = new Set(args.excludeTools.split(",").map((s) => s.trim()));
251	    tools = tools.filter((t) => !deny.has(t.name));
252	  }
253	  return tools;
