331	  // Enter alternate screen + hide cursor BEFORE render() so Ink's first paint
332	  // lands in the alternate buffer (otherwise the screen is blank until a key is pressed).
333	  process.stdout.write("\u001b[?1049h");
334	  process.stdout.write("\u001b[?25l");
