366	    const key = args[1];
367	    if (!key) {
368	      process.stderr.write("usage: minima config get <KEY>\n");
369	      return 2;
370	    }
371	    process.stdout.write(`${(await storeGet(key)) ?? ""}\n`);
372	    return 0;
