375	  for (const section of SECTIONS) {
376	    process.stdout.write(`\n# ${section.title}\n`);
377	    for (const f of section.fields) {
378	      const val = await storeGet(f.key);
379	      const shown = f.secret ? mask(val) : (val ?? "");
380	      process.stdout.write(`${f.key}=${shown}\n`);
381	    }
382	  }
383	  process.stdout.write("\nUse `minima config set <KEY> <value>` to store a credential.\n");
384	  return 0;
385	}
